class Solution {
public:
    int uniquePaths(int m, int n) {
        int numerator = m+n-2;
        int denominator = min(n-1,m-1);
        double solution = 1;

        for(int i = 0; i < min(n-1,m-1); i++)
        solution = solution * numerator-- / denominator--;

        return solution;

    }
};

class Solution {
public:
    int uniquePaths(int m, int n) {
        int numerator = m+n-2;
        int denominator = min(n-1,m-1);
        double solution = 1;

        for(int i = 0; i < min(n-1,m-1); i++)
        solution = solution * numerator-- / denominator--;

        return round(solution);

    }
};
